// Calendar Availability Analyzer Tool
const listingIds = $fromAI('listing_ids', 'comma-separated list of Airbnb listing IDs to analyze');
const city = $fromAI('city', 'the city being analyzed');

try {
  const ids = listingIds.split(',').map(id => id.trim()).slice(0, 10);
  const results = [];
  const today = new Date();
  const thirtyDaysOut = new Date(today.getTime() + (30 * 24 * 60 * 60 * 1000));
  const sixtyDaysOut = new Date(today.getTime() + (60 * 24 * 60 * 60 * 1000));

  for (const listingId of ids) {
    try {
      const mockCalendarData = generateMockCalendarData(listingId, today, sixtyDaysOut);

      const thirtyDayBookings = calculateBookedDays(mockCalendarData, today, thirtyDaysOut);
      const sixtyDayBookings = calculateBookedDays(mockCalendarData, today, sixtyDaysOut);

      const thirtyDayRate = (thirtyDayBookings / 30) * 100;
      const sixtyDayRate = (sixtyDayBookings / 60) * 100;

      const meets75_55Rule = thirtyDayRate >= 75 && sixtyDayRate >= 55;

      results.push({
        listingId,
        thirtyDayOccupancy: Math.round(thirtyDayRate * 10) / 10,
        sixtyDayOccupancy: Math.round(sixtyDayRate * 10) / 10,
        meets75_55Rule,
        bookedDays30: thirtyDayBookings,
        bookedDays60: sixtyDayBookings,
        totalDays30: 30,
        totalDays60: 60
      });
    } catch (error) {
      console.error(`Error analyzing listing ${listingId}:`, error.message);
    }
  }

  const totalListings = results.length;
  const qualifyingListings = results.filter(r => r.meets75_55Rule).length;
  const averageOccupancy30 = results.reduce((sum, r) => sum + r.thirtyDayOccupancy, 0) / totalListings;
  const averageOccupancy60 = results.reduce((sum, r) => sum + r.sixtyDayOccupancy, 0) / totalListings;

  const marketSummary = {
    city,
    totalListingsAnalyzed: totalListings,
    listingsMeeting75_55Rule: qualifyingListings,
    marketScore: Math.round((qualifyingListings / totalListings) * 100),
    averageOccupancy30Day: Math.round(averageOccupancy30 * 10) / 10,
    averageOccupancy60Day: Math.round(averageOccupancy60 * 10) / 10,
    recommendationLevel: qualifyingListings >= 5 ? 'High Potential' : qualifyingListings >= 2 ? 'Moderate Potential' : 'Low Potential'
  };

  return {
    success: true,
    marketSummary,
    listingResults: results.slice(0, 5),
    analysisDate: new Date().toISOString()
  };

} catch (error) {
  return {
    success: false,
    error: error.message,
    city: city || 'Unknown'
  };
}

function generateMockCalendarData(listingId, startDate, endDate) {
  const data = [];
  const seed = parseInt(listingId.slice(-3)) || 123;
  let random = seed;

  for (let d = new Date(startDate); d <= endDate; d.setDate(d.getDate() + 1)) {
    random = (random * 1103515245 + 12345) & 0x7fffffff;
    const bookingProbability = 0.6 + (random % 100) / 250;
    const isBooked = (random % 100) / 100 < bookingProbability;

    data.push({
      date: new Date(d).toISOString().split('T')[0],
      available: !isBooked,
      booked: isBooked
    });
  }

  return data;
}

function calculateBookedDays(calendarData, startDate, endDate) {
  return calendarData.filter(day => {
    const dayDate = new Date(day.date);
    return dayDate >= startDate && dayDate <= endDate && day.booked;
  }).length;
}

const analysisData = JSON.parse($fromAI('analysis_data', 'JSON string containing market analysis results'));
const city = $fromAI('city', 'the city being analyzed');

try {
  const { marketSummary, listingResults } = analysisData;

  const report = {
    title: `Airbnb Market Analysis: ${city}`,
    executiveSummary: {
      marketScore: marketSummary.marketScore,
      recommendation: marketSummary.recommendationLevel,
      keyInsight: generateKeyInsight(marketSummary),
      investmentReadiness: marketSummary.marketScore >= 40 ? 'Ready for Investment' : 'Requires Further Analysis'
    },

    marketMetrics: {
      totalProperties: marketSummary.totalListingsAnalyzed,
      qualifyingProperties: marketSummary.listingsMeeting75_55Rule,
      qualificationRate: `${marketSummary.marketScore}%`,
      avgOccupancy30Days: `${marketSummary.averageOccupancy30Day}%`,
      avgOccupancy60Days: `${marketSummary.averageOccupancy60Day}%`
    },

    topPerformers: listingResults
      .filter(listing => listing.meets75_55Rule)
      .sort((a, b) => (b.thirtyDayOccupancy + b.sixtyDayOccupancy) - (a.thirtyDayOccupancy + a.sixtyDayOccupancy))
      .slice(0, 3)
      .map(listing => ({
        listingId: listing.listingId,
        occupancyScore: Math.round(((listing.thirtyDayOccupancy + listing.sixtyDayOccupancy) / 2) * 10) / 10,
        thirtyDayRate: `${listing.thirtyDayOccupancy}%`,
        sixtyDayRate: `${listing.sixtyDayOccupancy}%`,
        status: 'Meets 75/55 Rule ✅'
      })),

    recommendations: generateRecommendations(marketSummary, listingResults),

    nextSteps: [
      'Study the top-performing properties for common characteristics',
      'Analyze pricing patterns of qualifying listings',
      'Research property types and amenities that drive bookings',
      'Consider neighborhood factors and proximity to attractions',
      'Evaluate local regulations and permitting requirements'
    ],

    reportMetadata: {
      generatedAt: new Date().toISOString(),
      analysisMethod: '75/55 Occupancy Rule',
      dataSource: 'Airbnb Calendar Analysis',
      marketConfidence: calculateMarketConfidence(marketSummary)
    }
  };

  return {
    success: true,
    report,
    formattedReport: formatReportForDisplay(report)
  };

} catch (error) {
  return {
    success: false,
    error: error.message,
    city: city || 'Unknown'
  };
}

function generateKeyInsight(summary) {
  if (summary.marketScore >= 60) {
    return `Strong market with ${summary.marketScore}% of properties meeting demand criteria. High investment potential.`;
  } else if (summary.marketScore >= 30) {
    return `Moderate market showing ${summary.marketScore}% qualification rate. Selective investment opportunities available.`;
  } else {
    return `Challenging market with only ${summary.marketScore}% meeting criteria. Consider alternative locations.`;
  }
}

function generateRecommendations(summary, listings) {
  const recommendations = [];

  if (summary.marketScore >= 50) {
    recommendations.push('✅ Market shows strong demand - proceed with property search');
    recommendations.push('🎯 Focus on property types similar to top performers');
  } else if (summary.marketScore >= 25) {
    recommendations.push('⚠️ Market shows moderate demand - be selective in property choice');
    recommendations.push('🔍 Research seasonal trends and local events that drive bookings');
  } else {
    recommendations.push('❌ Market shows low demand - consider alternative markets');
    recommendations.push('📊 Analyze longer-term trends before investing');
  }

  if (summary.averageOccupancy30Day > summary.averageOccupancy60Day + 10) {
    recommendations.push('📈 Short-term booking strength suggests seasonal or event-driven demand');
  }

  return recommendations;
}

function calculateMarketConfidence(summary) {
  const sampleSize = summary.totalListingsAnalyzed;
  const qualificationRate = summary.marketScore;

  if (sampleSize >= 15 && qualificationRate >= 40) return 'High';
  if (sampleSize >= 10 && qualificationRate >= 25) return 'Medium';
  return 'Low';
}

function formatReportForDisplay(report) {
  return `# 🏠 ${report.title}\n\n## 📊 Executive Summary\n- **Market Score:** ${report.executiveSummary.marketScore}%\n- **Recommendation:** ${report.executiveSummary.recommendation}\n- **Investment Status:** ${report.executiveSummary.investmentReadiness}\n\n## 📈 Key Metrics\n- Properties Analyzed: ${report.marketMetrics.totalProperties}\n- Meeting 75/55 Rule: ${report.marketMetrics.qualifyingProperties} (${report.marketMetrics.qualificationRate})\n- Avg 30-Day Occupancy: ${report.marketMetrics.avgOccupancy30Days}\n- Avg 60-Day Occupancy: ${report.marketMetrics.avgOccupancy60Days}\n\n## 🏆 Top Performers\n${report.topPerformers.map(p => `- Listing ${p.listingId}: ${p.occupancyScore}% avg occupancy ${p.status}`).join('\n')}\n\n## 💡 Recommendations\n${report.recommendations.join('\n')}\n\n## 🎯 Next Steps\n${report.nextSteps.map((step, i) => `${i + 1}. ${step}`).join('\n')}\n\n---\n*Analysis completed at ${new Date(report.reportMetadata.generatedAt).toLocaleString()}*`;
}

try {
  const today = new Date();
  const thirtyDaysOut = new Date(today.getTime() + (30 * 24 * 60 * 60 * 1000));
  const sixtyDaysOut = new Date(today.getTime() + (60 * 24 * 60 * 60 * 1000));

  const formatDate = (date) => date.toISOString().split('T')[0];

  return {
    success: true,
    today: formatDate(today),
    thirtyDayRange: {
      start: formatDate(today),
      end: formatDate(thirtyDaysOut),
      totalDays: 30
    },
    sixtyDayRange: {
      start: formatDate(today),
      end: formatDate(sixtyDaysOut),
      totalDays: 60
    },
    analysisWindow: {
      description: '75/55 Rule Analysis Window',
      criteria: {
        shortTerm: 'Minimum 75% occupancy in next 30 days',
        longTerm: 'Minimum 55% occupancy in next 60 days'
      }
    }
  };

} catch (error) {
  return {
    success: false,
    error: error.message
  };
}
